"""SQLAlchemy ORM models — generated by doql."""
from sqlalchemy import Column, String, Integer, Float, Boolean, Text, Date, DateTime, JSON, ForeignKey
from sqlalchemy.orm import relationship
from database import Base


class Product(Base):
    __tablename__ = "products"

    id = Column(String(36), primary_key=True)
    name = Column(String(255))
    slug = Column(String(255), unique=True)
    description = Column(Text, nullable=True)
    price = Column(String(255))
    currency = Column(String(255), nullable=True)
    stock = Column(Integer, nullable=True, default=0)
    category = Column(String(255), nullable=True)
    images = Column(JSON, nullable=True)
    active = Column(Boolean, nullable=True, default=True)
    created = Column(DateTime, nullable=True)
    updated = Column(DateTime, nullable=True)


class Customer(Base):
    __tablename__ = "customers"

    id = Column(String(36), primary_key=True)
    email = Column(String(255), unique=True)
    name = Column(String(255))
    phone = Column(String(255), nullable=True)
    address = Column(JSON, nullable=True)
    created = Column(DateTime, nullable=True)


class Order(Base):
    __tablename__ = "orders"

    id = Column(String(36), primary_key=True)
    customer = Column(String(255))
    status = Column(String(255), nullable=True)
    items = Column(JSON)
    total = Column(String(255))
    currency = Column(String(255), nullable=True)
    shipping_address = Column(JSON, nullable=True)
    payment_method = Column(String(255), nullable=True)
    paid_at = Column(DateTime, nullable=True)
    shipped_at = Column(DateTime, nullable=True)
    created = Column(DateTime, nullable=True)


class CartItem(Base):
    __tablename__ = "cart_items"

    id = Column(String(36), primary_key=True)
    session_id = Column(String(255))
    product = Column(String(255))
    quantity = Column(Integer, nullable=True, default=1)
    created = Column(DateTime, nullable=True)
